from dataclasses import dataclass, field
from typing import Optional
from enum import Enum
import uuid

class GoalStatus(Enum):
    PENDING = "pending"
    IN_PROGRESS = "in_progress"
    ACHIEVED = "achieved"
    FAILED = "failed"
    ABANDONED = "abandoned"

@dataclass
class Goal:
    description: str
    success_criterion: str       # what must be true for this goal to be complete
    priority: int = 5            # 1 (highest) … 10 (lowest)
    parent_id: Optional[str] = None
    id: str = field(default_factory=lambda: str(uuid.uuid4())[:8])
    status: GoalStatus = GoalStatus.PENDING
    result: Optional[str] = None
    sub_goals: list["Goal"] = field(default_factory=list)

    def is_terminal(self) -> bool:
        return self.status in (GoalStatus.ACHIEVED, GoalStatus.FAILED, GoalStatus.ABANDONED)

class GoalStack:
    def __init__(self):
        self._stack: list[Goal] = []

    def push(self, goal: Goal) -> None:
        self._stack.append(goal)

    def peek(self) -> Optional[Goal]:
        return self._stack[-1] if self._stack else None

    def pop(self) -> Optional[Goal]:
        return self._stack.pop() if self._stack else None

    def is_empty(self) -> bool:
        return len(self._stack) == 0

    def depth(self) -> int:
        return len(self._stack)

    def summary(self) -> str:
        return " → ".join(f"[{g.description[:40]}]" for g in self._stack)
